```class Solution {
    public int getMinSwaps(String num, int k) {
        int n = num.length();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = num.charAt(i) - '0';
        }
        Arrays.sort(arr);
        int swaps = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] != num.charAt(i) - '0') {
                int j = i;
                while (arr[j] != num.charAt(j) - '0') {
                    j++;
                }
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
                swaps++;
            }
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] == num.charAt(i) - '0') {
                res++;
            } else {
                break;
            }
        }
        return res + k - 1;
    }
}```
